function Home() {
  return (
    <div className="w-full h-[100vh] flex items-center justify-center p-4 md:p-10 relative">
      <div
        className="absolute top-0 left-0 w-full h-full"
        style={{
          backgroundImage: "url('/fondo6.jpg')",
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          opacity: 0.4,
        }}
      />
      <div className="w-full h-full z-10 flex flex-col md:flex-row items-center justify-center md:justify-between gap-10">
        {/* Images left */}
        <div className="h-full relative flex items-center justify-center md:justify-start">
          <div className="relative flex flex-col items-center md:ml-10">
            {/* Primera imagen */}
            <img
              id="image-1"
              className="rounded-lg transition-transform transform mb-5 md:mb-0"
              width={250}
              height={200}
              src="/Foto1.HEIC"
              alt="Imagen 1"
            />
            {/* Segunda imagen */}
            <img
              id="image-2"
              className="rounded-lg absolute animate-float"
              width={120}
              height={120}
              style={{
                top: '50%',
                left: 'calc(-35%)',
              }}
              src="/Foto1.HEIC"
              alt="Imagen 2"
            />
            {/* Tercera imagen */}
            <img
              id="image-3"
              className="rounded-lg absolute animate-float"
              width={120}
              height={120}
              style={{
                top: '90%',
                left: '50%',
                transform: 'translateX(-50%)',
              }}
              src="/Foto2.HEIC"
              alt="Imagen 3"
            />
          </div>
        </div>

        {/* Text center */}
        <div className="h-full flex flex-col justify-center items-center gap-5 text-center">
          <h3 className="text-[#6d7561] text-2xl sm:text-3xl md:text-3xl font-medium">
            ¡Los invitamos a festejar nuestra boda!
          </h3>
          <h1 className="text-[#6d7561] text-3xl sm:text-4xl md:text-5xl font-bold">
            Anto & Kevin
          </h1>
          <a
            href="#ConfirmAttendance"
            className="text-[#6d7561] text-xl sm:text-2xl underline hover:text-[#6d756190]"
          >
            {`Confirmar asistencia ${'>'}`}
          </a>
        </div>

        {/* Images right */}
        <div className="h-full relative flex items-center justify-center md:justify-end">
          <div className="relative flex flex-col items-center md:mr-10">
            <img
              className="rounded-lg"
              width={250}
              height={200}
              src="/Foto3.JPEG"
              alt="Imagen 1"
            />
            <img
              width={150}
              height={150}
              className="rounded-lg absolute animate-float"
              style={{
                top: 'calc(50% - 75px)',
                right: 'calc(-35%)',
              }}
              src="/Foto4.JPEG"
              alt="Imagen 2"
            />
          </div>
        </div>
      </div>
    </div>
  );
}

export default Home;
